// client/src/components/home/HomeScreen.js
import React from 'react';
import Button from '../ui/Button';

const HomeScreen = ({
  buildings,
  resources,
  onCollectResource,
  onUpgradeBuilding,
  playerLevel
}) => {
  const mainHouse = buildings.find(b => b.id === 'main-house');

  return (
    <div className="min-h-screen pt-16 pb-20 px-4">
      <div className="mb-6">
        <h1 className="text-2xl font-bold mb-2">Кошачья Империя</h1>
        <p className="text-gray-600">Уровень игрока: {playerLevel}</p>
      </div>

      <div className="mb-8">
        <h2 className="text-xl font-semibold mb-4">Ваше поселение</h2>
        <div className="relative w-full h-64 bg-green-100 rounded-lg overflow-hidden">
          {/* Здесь будет отображаться карта поселения */}
          <div className="absolute" style={{
            left: `${mainHouse?.positionX || 50}%`,
            top: `${mainHouse?.positionY || 50}%`,
            transform: 'translate(-50%, -50%)'
          }}>
            {mainHouse && (
              <div className="flex flex-col items-center">
                <img 
                  src={mainHouse.levels[mainHouse.currentLevel || 0].imageUrl || '/assets/images/buildings/house-basic.png'} 
                  alt="Дом" 
                  className="w-20 h-20 object-contain"
                />
                <span className="bg-white px-2 py-1 rounded text-xs mt-1">
                  {mainHouse.name} (Ур. {mainHouse.currentLevel || 0})
                </span>
              </div>
            )}
          </div>

          {/* Добавление других зданий будет здесь */}

          {/* Ресурсы на карте */}
          <div className="absolute bottom-4 right-4 flex flex-col gap-2">
            <Button
              onClick={() => onCollectResource('wood')}
              className="flex items-center gap-2"
            >
              <span>🪵</span> Собрать дерево
            </Button>
            <Button
              onClick={() => onCollectResource('fish')}
              className="flex items-center gap-2"
            >
              <span>🐟</span> Поймать рыбу
            </Button>
          </div>
        </div>
      </div>

      <div className="mb-8">
        <h2 className="text-xl font-semibold mb-2">Улучшение дома</h2>
        {mainHouse && mainHouse.currentLevel < mainHouse.levels.length - 1 && (
          <div className="bg-white p-4 rounded-lg shadow">
            <p className="mb-2">
              Уровень {mainHouse.currentLevel + 1} — увеличит вместимость хранилища на{' '}
              {mainHouse.levels[mainHouse.currentLevel + 1].bonuses.storageCapacity - 
                mainHouse.levels[mainHouse.currentLevel].bonuses.storageCapacity}
            </p>

            <div className="flex gap-3 mb-3">
              <div className="flex items-center gap-1">
                <span>🪵</span>
                <span>
                  {mainHouse.levels[mainHouse.currentLevel + 1].upgradeCost.wood}
                </span>
              </div>
              <div className="flex items-center gap-1">
                <span>🐟</span>
                <span>
                  {mainHouse.levels[mainHouse.currentLevel + 1].upgradeCost.fish}
                </span>
              </div>
            </div>

            <Button
              onClick={() => onUpgradeBuilding('main-house')}
              disabled={
                resources.wood.amount < mainHouse.levels[mainHouse.currentLevel + 1].upgradeCost.wood ||
                resources.fish.amount < mainHouse.levels[mainHouse.currentLevel + 1].upgradeCost.fish
              }
            >
              Улучшить
            </Button>
          </div>
        )}

        {mainHouse && mainHouse.currentLevel >= mainHouse.levels.length - 1 && (
          <p className="text-center py-4">
            Дом улучшен до максимального уровня!
          </p>
        )}
      </div>

      <div>
        <h2 className="text-xl font-semibold mb-2">Доступные постройки</h2>
        <div className="grid grid-cols-2 gap-4">
          {buildings
            .filter(b => b.id !== 'main-house' && b.unlockLevel <= playerLevel)
            .map(building => (
              <div key={building.id} className="bg-white p-3 rounded-lg shadow">
                <h3 className="font-medium mb-1">{building.name}</h3>
                <p className="text-xs text-gray-600 mb-2">{building.description}</p>

                {!building.isBuilt ? (
                  <Button
                    onClick={() => onUpgradeBuilding(building.id)}
                    disabled={
                      resources.wood.amount < building.levels[0].upgradeCost.wood ||
                      resources.fish.amount < building.levels[0].upgradeCost.fish
                    }
                    className="w-full text-xs"
                  >
                    Построить
                  </Button>
                ) : (
                  <p className="text-center text-green-600 text-xs">Построено</p>
                )}
              </div>
            ))}
        </div>
      </div>
    </div>
  );
};

export default HomeScreen;
